import React, { useState, useEffect } from "react";
import dayjs from "dayjs";
import {
  Chart as ChartJS,
  CategoryScale,
  LinearScale,
  BarElement,
  Tooltip,
  Legend,
} from "chart.js";
import { Bar } from "react-chartjs-2";

ChartJS.register(CategoryScale, LinearScale, BarElement, Tooltip, Legend);

const commonGrid = {
  grid: {
    display: false,
    drawBorder: false,
  },
  ticks: {
    font: { size: 11 },
  },
};

function Dashboard() {
  const [isMobile, setIsMobile] = useState(window.innerWidth < 768);

  useEffect(() => {
    const handleResize = () => {
      setIsMobile(window.innerWidth < 768);
    };
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const barThickness = isMobile ? 20 : 50;
  const maxBarThickness = isMobile ? 20 : 55;

  /* ================= STATIC ADMIN DATA ================= */

  const adminProfile = {
    name: "Admin User",
    lastUpdated: new Date(),
  };

  const summaryCards = {
    totalUsers: 1250,
    totalLeads: 842,
    totalRevenue: 2450000,
    totalSupportTickets: 128,
  };

  const supportData = {
    pending: 24,
    resolved: 104,
  };

  /* ================= PAYMENTS OVERVIEW CHART ================= */

  const paymentsYear = new Date().getFullYear();

  const months = ["Jan", "Feb", "Mar", "Apr", "May", "Jun"];

  const paymentData = [320000, 450000, 380000, 510000, 420000, 600000];
  const commissionData = paymentData.map((amt) =>
    Number(((amt * 10) / 100).toFixed(0))
  );

  const paymentsChartData = {
    labels: months,
    datasets: [
      {
        label: "Total Revenue (₹)",
        data: paymentData,
        backgroundColor: "#19875475",
        borderRadius: 8,
        barThickness,
        maxBarThickness,
      },
      {
        label: "Commission (10%)",
        data: commissionData,
        backgroundColor: "#ffc10775",
        borderRadius: 8,
        barThickness,
        maxBarThickness,
      },
    ],
  };

  const paymentsChartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      title: {
        display: true,
        text: `Revenue Overview (${paymentsYear})`,
      },
    },
    scales: {
      x: { ...commonGrid },
      y: {
        beginAtZero: true,
        ...commonGrid,
        ticks: {
          callback: (v) => `₹${v / 1000}k`,
        },
      },
    },
  };

  /* ================= LEADS CHART ================= */

  const leadsChartData = {
    labels: months,
    datasets: [
      {
        label: "Total Leads",
        data: [120, 150, 130, 180, 170, 210],
        backgroundColor: "#0d6efd65",
        borderRadius: 8,
        barThickness,
        maxBarThickness,
      },
      {
        label: "Approved Leads",
        data: [80, 110, 95, 140, 130, 170],
        backgroundColor: "#19875475",
        borderRadius: 8,
        barThickness,
        maxBarThickness,
      },
    ],
  };

  const leadsChartOptions = {
    responsive: true,
    maintainAspectRatio: false,
    plugins: {
      title: {
        display: true,
        text: `Leads Overview (${paymentsYear})`,
      },
    },
    scales: {
      x: { ...commonGrid },
      y: {
        beginAtZero: true,
        ...commonGrid,
      },
    },
  };

  return (
    <div className="container py-3">
      {/* Header */}
      <h4 className="fw-bold fs-3">
        Welcome, {adminProfile.name}
      </h4>
      <small>
        Last Updated:{" "}
        {dayjs(adminProfile.lastUpdated).format("DD MMM YYYY, hh:mm A")}
      </small>

      {/* Summary Cards */}
      <div className="row g-3 mt-3">
        <div className="col-md-3 col-6">
          <div className="p-3 border rounded bg-body">
            <small>Total Users</small>
            <h5>{summaryCards.totalUsers}</h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 border rounded bg-body">
            <small>Total Leads</small>
            <h5>{summaryCards.totalLeads}</h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 border rounded bg-body">
            <small>Total Revenue</small>
            <h5>
              ₹{summaryCards.totalRevenue.toLocaleString("en-IN")}
            </h5>
          </div>
        </div>

        <div className="col-md-3 col-6">
          <div className="p-3 border rounded bg-body">
            <small>Support Tickets</small>
            <h5>{summaryCards.totalSupportTickets}</h5>
          </div>
        </div>
      </div>

      {/* Charts */}
      <div className="row g-3 mt-4">
        <div className="col-lg-4 col-12">
          <div className="border rounded p-3 bg-body h-100">
            <div style={{ height: "300px" }}>
              <Bar data={leadsChartData} options={leadsChartOptions} />
            </div>
          </div>
        </div>

        <div className="col-lg-8 col-12">
          <div className="border rounded p-3 bg-body h-100">
            <div style={{ height: "300px" }}>
              <Bar
                data={paymentsChartData}
                options={paymentsChartOptions}
              />
            </div>
          </div>
        </div>
      </div>

      {/* Support Overview */}
      <div className="row mt-4">
        <div className="col-md-6 col-12">
          <div className="p-3 border-start border-5 border-warning rounded bg-body">
            <h5>Support Overview</h5>
            <p className="mb-1">Pending: {supportData.pending}</p>
            <p className="mb-0">Resolved: {supportData.resolved}</p>
          </div>
        </div>
      </div>
    </div>
  );
}

export default Dashboard;
